// // When a = 1, q should be 5db5; when a = 6, q should be 2915; when a = 7, q should be 4a50; when a = 0, q should be a7db; when a = 2, q should be 8a47; when a = 3, q should be 051d; when a = 4, q should be 483b; when a = 5, q should be b7c9.
module top_module (
    input [2:0] a,
    output reg [15:0] q
);  always @(*)
    case (a)
      0: q = 16'h5db5;
      1: q = 16'ha7db;
      2: q = 16'hb7c9;
      3: q = 16'h8a47;
      4: q = 16'h483b;
      5: q = 16'h051d;
      6: q = 16'h2915;
      7: q = 16'h4a50;
    endcase

endmodule
